#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

int n;
char s[N];
double f[N][2];

int main(){
    scanf("%d%s",&n,s+1);
    for(int i=1;i<=n;i++){
        if(s[i]=='o'){
            f[i][0]=f[i-1][0]+1;
            f[i][1]=f[i-1][1]+2*f[i-1][0]+1;
        }else if(s[i]=='x'){
            f[i][0]=0;
            f[i][1]=f[i-1][1];
        }else{
            f[i][0]=0.5*(f[i-1][0]+1);
            f[i][1]=f[i-1][0]+f[i-1][1]+0.5;
        }
    }
    printf("%.4lf",f[n][1]);
    return 0;
}
